class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.history = [];
        this.state = {
            th1: (initialInputs.angle1 * Math.PI) / 180,
            th2: (initialInputs.angle2 * Math.PI) / 180,
            v1: 0,
            v2: 0
        };
        this.lastAngles = JSON.stringify({ a1: initialInputs.angle1, a2: initialInputs.angle2 });
        this.resize();
        window.addEventListener('resize', () => this.resize());
    }

    resize() {
        this.canvas.width = this.container.clientWidth;
        this.canvas.height = this.container.clientHeight;
    }

    update(inputs) {
        const currentAngles = JSON.stringify({ a1: inputs.angle1, a2: inputs.angle2 });
        if (this.lastAngles !== currentAngles) {
            this.state.th1 = (inputs.angle1 * Math.PI) / 180;
            this.state.th2 = (inputs.angle2 * Math.PI) / 180;
            this.state.v1 = 0;
            this.state.v2 = 0;
            this.history = [];
            this.lastAngles = currentAngles;
        }

        const m1 = inputs.mass1;
        const m2 = inputs.mass2;
        const l1 = inputs.length1;
        const l2 = inputs.length2;
        const g = inputs.gravity;
        const damp = 1 - inputs.damping;

        let { th1, th2, v1, v2 } = this.state;

        for (let i = 0; i < 2; i++) {
            let num1 = -g * (2 * m1 + m2) * Math.sin(th1);
            let num2 = -m2 * g * Math.sin(th1 - 2 * th2);
            let num3 = -2 * Math.sin(th1 - th2) * m2;
            let num4 = v2 * v2 * l2 + v1 * v1 * l1 * Math.cos(th1 - th2);
            let den = l1 * (2 * m1 + m2 - m2 * Math.cos(2 * th1 - 2 * th2));
            let a1_a = (num1 + num2 + num3 * num4) / den;

            num1 = 2 * Math.sin(th1 - th2);
            num2 = (v1 * v1 * l1 * (m1 + m2));
            num3 = g * (m1 + m2) * Math.cos(th1);
            num4 = v2 * v2 * l2 * m2 * Math.cos(th1 - th2);
            den = l2 * (2 * m1 + m2 - m2 * Math.cos(2 * th1 - 2 * th2));
            let a2_a = (num1 * (num2 + num3 + num4)) / den;

            v1 += a1_a;
            v2 += a2_a;
            v1 *= damp;
            v2 *= damp;
            th1 += v1;
            th2 += v2;
        }

        this.state = { th1, th2, v1, v2 };

        const ctx = this.ctx;
        ctx.fillStyle = '#0f172a';
        ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

        const cx = this.canvas.width / 2;
        const cy = this.canvas.height / 2.5;

        const x1 = l1 * Math.sin(th1);
        const y1 = l1 * Math.cos(th1);
        const x2 = x1 + l2 * Math.sin(th2);
        const y2 = y1 + l2 * Math.cos(th2);

        this.history.push({ x: x2 + cx, y: y2 + cy });
        if (this.history.length > 500) this.history.shift();

        if (this.history.length > 1) {
            ctx.lineWidth = 1.5;
            for (let i = 1; i < this.history.length; i++) {
                const ratio = i / this.history.length;
                ctx.strokeStyle = `rgba(59, 130, 246, ${ratio * 0.8})`;
                ctx.beginPath();
                ctx.moveTo(this.history[i - 1].x, this.history[i - 1].y);
                ctx.lineTo(this.history[i].x, this.history[i].y);
                ctx.stroke();
            }
        }

        ctx.strokeStyle = '#94a3b8';
        ctx.lineWidth = 4;
        ctx.lineCap = 'round';
        ctx.beginPath();
        ctx.moveTo(cx, cy);
        ctx.lineTo(x1 + cx, y1 + cy);
        ctx.lineTo(x2 + cx, y2 + cy);
        ctx.stroke();

        ctx.fillStyle = '#3b82f6';
        ctx.beginPath();
        ctx.arc(x1 + cx, y1 + cy, 8, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#3b82f6';
        ctx.fillStyle = '#60a5fa';
        ctx.beginPath();
        ctx.arc(x2 + cx, y2 + cy, 10, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 0;

        ctx.fillStyle = '#f8fafc';
        ctx.font = '14px Inter, system-ui';
        ctx.textAlign = 'center';
        ctx.fillText(`Angular Vel 1: ${v1.toFixed(3)} rad/s`, cx, this.canvas.height - 40);
        ctx.fillText(`Angular Vel 2: ${v2.toFixed(3)} rad/s`, cx, this.canvas.height - 20);
    }
}
